INSERT INTO `about_headmasters` (`id`, `image`, `headline`, `message`, `created_at`, `updated_at`) VALUES
(2, 'headmastermessage/EqsZ8sWmefsEtXBLeLIYpYsFZzmYwN3V6ZdOjcGB.jpg', 'শিক্ষা শুধু জীবন প্রস্তুতির উপায় নয়, তা জীবন-যাপনের প্রণালীও বটে।\n', 'শিক্ষাকে জীবনব্যাপি অনুসরণীয় প্রক্রিয়া হিসেবে দেখতে হবে এবং অভিজ্ঞতাকে শিক্ষা লাভের স্বাভাবিক কৌশল হিসেবে বিবেচনায় রাখতে হবে। আধুনিক শিক্ষা দর্শনে শিক্ষার্থীদের ব্যক্তিসত্তা বিকাশের ওপর বিশেষ গুরুত্ব আরোপ করা হয়েছে। শিক্ষার্থীদের ব্যক্তি স্বাতন্ত্রবোধ জাগ্রত করা এবং তাকে আত্মসত্তার আস্থাবান করে তোলাই শিক্ষার প্রধান লক্ষ্য হওয়া উচিত।\n<br><br>\nআমাদের দেশে বর্তমানে তিন ধরনের শিক্ষা ব্যবস্থা প্রচলিত রয়েছে। অনানুষ্ঠানিক শিক্ষা (Informal Education), আনুষ্ঠানিক শিক্ষা (Formal Education) এবং উপানুষ্ঠানিক শিক্ষা (Non Formal Education)। তবে আমাদের শিক্ষা কর্মক্ষেত্রে আনুষ্ঠানিক শিক্ষা (Formal Education) অধিকমাত্রায় প্রচলিত। আনুষ্ঠানিক শিক্ষা শ্রেণিভিত্তিক, স্তরভিত্তিক, পূর্ণকালীন, সুসংগঠিত এবং সুনিয়ন্ত্রিত শিক্ষা ব্যবস্থা। আইন-কানুন, রীতি-নীতি ও বিধি নিষেধ দ্বারা এ শিক্ষা ব্যবস্থা শৃঙ্খলিত।\n<br><br>\nআমাদের দেশে বর্তমানে তিন ধরনের শিক্ষা ব্যবস্থা প্রচলিত রয়েছে। অনানুষ্ঠানিক শিক্ষা (Informal Education), আনুষ্ঠানিক শিক্ষা (Formal Education) এবং উপানুষ্ঠানিক শিক্ষা (Non Formal Education)। তবে আমাদের শিক্ষা কর্মক্ষেত্রে আনুষ্ঠানিক শিক্ষা (Formal Education) অধিকমাত্রায় প্রচলিত। আনুষ্ঠানিক শিক্ষা শ্রেণিভিত্তিক, স্তরভিত্তিক, পূর্ণকালীন, সুসংগঠিত এবং সুনিয়ন্ত্রিত শিক্ষা ব্যবস্থা। আইন-কানুন, রীতি-নীতি ও বিধি নিষেধ দ্বারা এ শিক্ষা ব্যবস্থা শৃঙ্খলিত।\n<br><br>\nFormal Education বাস্তবায়নের জন্য উন্নত ও ভালোমানের শিক্ষা প্রতিষ্ঠান অপরিহার্য। সেদিক থেকে চাইল্ড কেয়ার হাই স্কুলের অবস্থান নান্দনিক পর্যায়ে রয়েছে। বর্তমান শিক্ষানীতি সঠিকভাবে পাঠ্যক্রম অনুসরণ, সৃজনশীল পদ্ধতির সঠিক প্রয়োগ ও তথ্য প্রযুক্তির সর্বোচ্চ ব্যবহারে  অনন্য দৃষ্টান্তের অধিকারী।\n<br><br>\nআরেক ধাপ এগিয়ে বলা যায় ২০-৩��� জনের আসন বিশিষ্ট, মাল্টিমিডিয়া ক্লাসরুম, স্মার্ট ক্লাসরুম, সমৃদ্ধ লাইব্রেরি ও বিজ্ঞানাগার,  ট্রান্সপোর্ট সুবিধা। সহশিক্ষা কার্যক্রমের জন্য কালচারাল একাডেমি, স্কাউটিং, ডিবেট ক্লাব, ল্যাংগুয়েজ ক্লাব, ক্যারিয়ার কাউন্সিলিং এবং সৃজনশীল ও ডিজিটাল কন্টেন্টের মাধ্যমে পাঠদানে পারদর্শী ছয় শতাধিক দক্ষ ও অভিজ্ঞ শিক্ষক রয়েছে। এই শিক্ষা প্রতিষ্ঠানকে আরো সমৃদ্ধ করেছে প্রাক্তন শিক্ষার্থীরা, যাদের অনেকেই আজ বাংলাদেশের বিভিন্ন পাবলিক ও প্রাইভেট বিশ্ববিদ্যালয়ের শিক্ষক, ডাক্তার, ইঞ্জিনিয়ার, আর্মি অফিসার হিসেবে দেশ সেবায় নিয়োজিত রয়েছে; এদের মধ্যে অনেকেই দেশ-বিদেশের সেরা শিক্ষা প্রতিষ্ঠানে অধ্যয়ন করছে।\n<br><br>\nসামগ্রিক অর্থে আমাদের শিক্ষার মান নতুন আলোর ঠিকানায় পৌঁছে দিতে হবে। সে প্রত্যাশায় আমরা প্রতিদিন শিক্ষার জন্য কাজ করে যাচ্ছি। আহ্বান জানাই, অভিভাবক ও শুভানুধ্যায়ী আপনারাও আমাদের সহযাত্রী হোন। সকল শিক্ষার্থী ও সম্মানিত অভিভাবকদের শুভেচ্ছা জানাচ্ছি।\n<br><br>\nআমরা গুণগত শিক্ষার পাশাপাশি নীতি ও নৈতিকতা সম্পন্ন আদর্শ মানুষ তৈরিতে বিশ্বাসি ।\n<br><br>\nসবার সুন্দর এবং মঙ্গলময় জীবন প্রত্যাশা করছি। আল্লাহ আমাদের সবার প্রতি সহায় হোন। আল্লাহ্ হাফেজ।', '2022-09-15 01:09:34', '2023-11-25 23:02:50');
